module pipelined_register (
    input clk,
    input reset,
    input [15:0] data_in,
    output [15:0] data_out
);

    reg [15:0] unused_pipeline [0:3];  // 4-stage unused_pipeline

    always @(posedge clk) begin
        if (reset) begin
            unused_pipeline[0] <= 16'b0;
            unused_pipeline[1] <= 16'b0;
            unused_pipeline[2] <= 16'b0;
            unused_pipeline[3] <= 16'b0;
        end else begin
            unused_pipeline[0] <= data_in;
            unused_pipeline[1] <= unused_pipeline[0];
            unused_pipeline[2] <= unused_pipeline[1];
            unused_pipeline[3] <= unused_pipeline[2];
        end
    end

    assign data_out = unused_pipeline[3];

endmodule
